#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 半导体芯片制造工艺.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="半导体芯片制造工艺"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 物理 / 器件可行性
  9.2 工艺整合与可制造性（DFM/PDK/DTCO）
  9.3 良率与缺陷诊断
  9.4 真节点 / 真成本换算（拆营销）
  9.5 设备 / 材料 / 供应链与国产替代 / 出口管制核查
  9.6 时效与路线图核查

背后的心智模型:
  • 物理硬约束 ⇄ 良率/成本经济约束（第一性双重张力）: 半导体工艺的每个决策都同时受两类硬约束——物理/化学/材料（量子隧穿、短沟道效应、RC 延迟、热预算、缺陷物理）与良率/成本经济（D0 缺陷密度、每片晶圆成本、wph、折旧）；摩尔定律首先是**经济命
  • 设备/工艺是必要非充分，良率 know-how 才是真壁垒: 能不能做先进制程，从来不是「有没有 EUV/光刻机」单一决定的——设备 + 材料 + 刻蚀/沉积 + 工艺整合 + 良率爬坡**五要素缺一不可**，而良率 ramp 的 know-how 是 silo
  • 微缩 = 不断加强栅对沟道的静电控制（thin body）: 器件架构演进有单一第一性逻辑——对抗短沟道效应靠「加强栅对沟道的静电控制」：平面 → FinFET（把沟道立成薄鳍三面环栅）→ GAA nanosheet（四面环栅）→ CFET（垂直堆叠），每代换的

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "物理 / 器件可行性"
  "工艺整合与可制造性（DFM/PDK/DTCO）"
  "良率与缺陷诊断"
  "真节点 / 真成本换算（拆营销）"
  "设备 / 材料 / 供应链与国产替代 / 出口管制核查"
  "时效与路线图核查"
)
declare -a DIM_QUESTIONS=(
  "目标的物理可行性——短沟道效应 / 静电控制（需要 FinFET/GAA/CFET 哪代栅控架构）、热预算、RC 延迟、缺陷物理、漏电/功耗。"
  "FEOL/MOL/BEOL 模块如何协同、PDK/设计规则是否就绪、DTCO/STCO 协同空间、是否单模块优化撞系统次优。"
  "良率现状与目标（D0 缺陷密度 / SPC）、缺陷分类与 commonality 空间签名、FA 根因路径、改善是否固化进 SPC/BKM。"
  "节点的真实尺度（gate pitch CPP / metal pitch MMP / 逻辑密度 MTr/mm²）+ 每晶体管成本 + PPAC，而非营销节点名。"
  "能否做某节点的五要素（设备 + 材料 + 刻蚀沉积 + 整合 + 良率）是否齐备、关键设备/材料的供应与垄断格局、出口管制（BIS entity list/ECCN）影响、国产替代真实代差。"
  "是否有最新进展——high-NA EUV ramp、GAA/CFET/BSPDN 量产时点、先进封装（HBM/CoWoS/hybrid bonding）、出口管制更新、新设备/材料。"
)
declare -a DIM_SOURCES=(
  "器件物理教材（Sze T04-S031）、Dennard scaling（T04-S004）、FinFET/GAA/CFET 谱系（T04-S009/T04-S023）、IRDS More Moore 章（T04-S007）。"
  "DTCO 顶会 short course（T04-S019）、代工 DTCO 技术博客（T04-S018）、PDK 指南（T06-S034/T06-S035）、Track 03 整合 workflow。"
  "良率方法学（May & Spanos T04-S034、D0 Murphy 模型 T06-S019、SIA yield enhancement T03-S003）、commonality/FA workflow（T03-S001/T03-S002）。"
  "TechInsights 拆解 / IC Knowledge 成本模型（T01-S018/T01-S019）、IRDS（T04-S007）、节点命名脱钩长稿（T06-S005/T06-S007）。"
  "设备/材料格局（Track 02：T02-S001/T02-S029）、BIS 管制原文（T06-S003/T06-S031）、SemiAnalysis/TechInsights 拆解（T01-S017）。"
  "IRDS 最新版（T06-S001）、IEDM/VLSI 顶会、SemiAnalysis/Semiconductor Engineering、ASML/imec 路线（T02-S005/T04-S023）。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "「物理上能否做、瓶颈在哪个效应、需要哪代器件架构」的判断 + 物理约束清单。"
  "「整合方案 + PDK/规则就绪度 + 协同优化点」的结构化结论。"
  "「良率瓶颈 + commonality 定位 + 根因 + 固化方案」的诊断结论。"
  "「真密度/真成本换算结果 + 跨厂可比结论 + 营销名脱钩提示」+ source。"
  "「五要素齐备度 + 卡点环节 + 管制/国产差距」的红绿灯结论 + 「业内估计」标注。"
  "「路线图/政策/封装是否有新变化 + 对当前判断的影响」+ \`last_checked\` 日期。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
